svg.script:
(function() {
  var ball = document.getElementById('ball');
  var paddle = document.getElementById('paddle');
  var bricks = Array.prototype.slice.call(document.querySelectorAll('#grid .brick'));

  var gridX = 110, gridY = 86, gridW = 686, gridH = 88;
  var paddleY = 242;
  var paddleW = 78, paddleH = 8;
  var r = 5.5;

  var x = 744;
  var y = 234;
  var vx = -2.65;
  var vy = -2.4;

  var paddleX = 706;
  var targetPaddleX = paddleX;
  var paused = false;

  var samePatternFrames = 0;
  var lastSignature = '';

  function sync() {
    ball.setAttribute('cx', x);
    ball.setAttribute('cy', y);
    paddle.setAttribute('x', paddleX);
    paddle.setAttribute('y', paddleY);
  }

  function clamp(v, a, b) {
    return Math.max(a, Math.min(b, v));
  }

  function rectHit(rx, ry, rw, rh) {
    var nx = clamp(x, rx, rx + rw);
    var ny = clamp(y, ry, ry + rh);
    var dx = x - nx;
    var dy = y - ny;
    return dx * dx + dy * dy <= r * r;
  }

  function reflectBrick(rx, ry, rw, rh) {
    var prevX = x - vx;
    var prevY = y - vy;
    var fromLeft = prevX + r <= rx;
    var fromRight = prevX - r >= rx + rw;
    var fromTop = prevY + r <= ry;
    var fromBottom = prevY - r >= ry + rh;

    if (fromLeft || fromRight) vx *= -1;
    if (fromTop || fromBottom) vy *= -1;
    if (!(fromLeft || fromRight || fromTop || fromBottom)) vy *= -1;
  }

  function resetBall() {
    x = paddleX + paddleW / 2;
    y = paddleY - r - 2;
    vx = (Math.random() > 0.5 ? 1 : -1) * 2.4;
    vy = -2.5;
  }

  function frame() {
    if (paused) return;

    // Slightly imperfect paddle so it doesn't settle too fast into a loop
    targetPaddleX = clamp(x - paddleW / 2, gridX, gridX + gridW - paddleW);
    paddleX += (targetPaddleX - paddleX) * 0.09;

    x += vx;
    y += vy;

    // Walls
    if (x - r <= gridX) {
      x = gridX + r;
      vx = Math.abs(vx);
    }
    if (x + r >= gridX + gridW) {
      x = gridX + gridW - r;
      vx = -Math.abs(vx);
    }
    if (y - r <= gridY) {
      y = gridY + r;
      vy = Math.abs(vy);
    }

    // Real paddle interaction
    if (rectHit(paddleX, paddleY, paddleW, paddleH) && vy > 0) {
      y = paddleY - r - 0.5;
      var hit = ((x - paddleX) / paddleW) - 0.5;
      var spin = (Math.random() - 0.5) * 0.55;
      vx = hit * 5.9 + spin;
      vy = -(2.35 + Math.min(1.7, Math.abs(hit) * 2.0));
      if (Math.abs(vx) < 0.75) vx += (vx < 0 ? -0.55 : 0.55);
    }

    // Brick collisions
    for (var i = 0; i < bricks.length; i++) {
      var b = bricks[i];
      if (b.dataset.alive !== '1') continue;
      var rx = +b.getAttribute('x');
      var ry = +b.getAttribute('y');
      var rw = +b.getAttribute('width');
      var rh = +b.getAttribute('height');
      if (rectHit(rx, ry, rw, rh)) {
        b.dataset.alive = '0';
        b.setAttribute('class', 'brick l0');
        reflectBrick(rx, ry, rw, rh);
        break;
      }
    }

    // Anti-loop nudge
    var signature = [
      Math.round(x / 14),
      Math.round(y / 14),
      Math.round(vx * 10) / 10,
      Math.round(vy * 10) / 10
    ].join('|');

    if (signature === lastSignature) {
      samePatternFrames++;
    } else {
      samePatternFrames = 0;
      lastSignature = signature;
    }

    if (samePatternFrames > 18) {
      vx += (Math.random() > 0.5 ? 0.22 : -0.22);
      vy += (Math.random() > 0.5 ? 0.08 : -0.08);
      samePatternFrames = 0;
    }

    // Miss -> reset
    if (y - r > paddleY + 28) {
      resetBall();
    }

    sync();
    requestAnimationFrame(frame);
  }

  document.documentElement.addEventListener('click', function() {
    paused = !paused;
    if (!paused) requestAnimationFrame(frame);
  });

  sync();
  requestAnimationFrame(frame);
})();
